module top_module(
                     input      rst,
                     input      reset_clk,
                     input      en,
                     input      d,
                     output reg q
                     );always @(posedge reset_clk or posedge rst) begin
      if (rst)
        q <= 1'b0;
      else if (en)
        q <= d;
   end
endmodule
